function getLastMoment(n, k, time) {
    const left = time.map((item, index) => [item[0] + item[2], index]);
    left.sort(([a], [b]) => a - b);
    let right = [];

    while (n) {
        while (right.length && right[0][0] <= left[0][0]) {
            let rightTop = right.shift();
            left.push([rightTop[0] + time[rightTop[1]][0] + time[rightTop[1]][2], rightTop[1]]);
            left.sort(([a], [b]) => a - b);
        }
        let leftTop = left.shift();
        time[leftTop[1]][2] += time[leftTop[1]][3] + time[leftTop[1]][0] + time[leftTop[1]][1];
        right.push([leftTop[0] + time[leftTop[1]][1], leftTop[1]]);
        right.sort(([a], [b]) => a - b);
        n--;
    }

    let lastMoment = -1;
    while (right.length) {
        let rightTop = right.shift();
        lastMoment = Math.max(lastMoment, time[rightTop[1]][2]);
    }
    return lastMoment;
}
```

    We will use two priority queues for workers at the left and right sides of the bridge. Initially, all workers are put in the left priority queue using their "total time to cross the bridge" as the key value. 

In a loop until all `n` boxes are moved, we perform the following steps:
1. Shift all waiting workers from the right priority queue (sorted by the return time from the old warehouse) to the left priority queue.
2. Shift the worker with the highest priority (lowest efficiency) from the left priority queue to the right priority queue (assign the task of moving the box for this worker)
3. We are decrementing the number of remaining boxes by 1.

In the end, we go through the right priority queue one more time, updating the maximum value while popping each worker from the queue. Since the boxes have been moved, workers in the right queue only need to put boxes in the new warehouse, and there is no need to worry about priority. The last moment at which the last worker reaches the left bank is equal to the maximum of their times on the bridge. We return this last moment value.

