    ```java
import java.util.*;

public int getLastMoment(int n, int k, int[][] time) {
    PriorityQueue<int[]> left = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
    PriorityQueue<int[]> right = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));

    for (int i = 0; i < k; i++) {
        left.offer(new int[]{time[i][0] + time[i][2], i});
    }

    while (n > 0) {
        while (!right.isEmpty() && right.peek()[0] <= left.peek()[0]) {
            int[] rightTop = right.poll();
            left.offer(new int[]{rightTop[0] + time[rightTop[1]][0] + time[rightTop[1]][2], rightTop[1]});
        }
        int[] leftTop = left.poll();
        time[leftTop[1]][2] += time[leftTop[1]][3] + time[leftTop[1]][0] + time[leftTop[1]][1];
        right.offer(new int[]{leftTop[0] + time[leftTop[1]][1], leftTop[1]});
        n--;
    }

    int lastMoment = -1;
    while (!right.isEmpty()) {
        lastMoment = Math.max(lastMoment, time[right.poll()[1]][2]);
    }
    return lastMoment;
}
```

